const today=new Date().toISOString().slice(0,10);
const verified=$('Read Verified Sheet').all().map(i=>i.json).filter(r=>String(r.processed_at||'').startsWith(today));
const flagged=$('Read Flagged Sheet').all().map(i=>i.json).filter(r=>String(r.processed_at||'').startsWith(today));
const needsReview=$('Read Needs Review Sheet').all().map(i=>i.json).filter(r=>String(r.processed_at||'').startsWith(today));
const totalCount=verified.length+flagged.length+needsReview.length;
const passRate=totalCount>0?((verified.length/totalCount)*100).toFixed(1):'0.0';
const totalAmount=verified.reduce((s,r)=>{const v=parseFloat(r.total_amount);return s+(isNaN(v)?0:v);},0);
const currencyMap={};
for(const r of verified){const c=r.currency||'UNKNOWN';if(!currencyMap[c])currencyMap[c]={count:0,total:0};currencyMap[c].count++;currencyMap[c].total+=parseFloat(r.total_amount)||0;}
const currencyRows=Object.entries(currencyMap).sort((a,b)=>b[1].total-a[1].total).map(([currency,d])=>({currency,count:d.count,total:d.total.toFixed(2)}));
const topErrors=flagged.flatMap(r=>(r.errors||'').split(' | ').filter(Boolean)).reduce((acc,e)=>{acc[e.trim()]=(acc[e.trim()]||0)+1;return acc;},{});
const avgConf=verified.length>0?Math.round(verified.reduce((s,r)=>s+(parseFloat(r.confidence_score)||0),0)/verified.length*100):null;
const dupCount=[...flagged,...needsReview].filter(r=>String(r.is_duplicate)==='true').length;
return [{json:{today,totalCount,verifiedCount:verified.length,flaggedCount:flagged.length,needsReviewCount:needsReview.length,passRate,totalAmount:totalAmount.toFixed(2),currencyRows,topErrors,avgConf,dupCount}}];

const d=$('Aggregate Stats').first().json;
const currTable=d.currencyRows.map(r=>'<tr><td style="padding:7px 14px;border-bottom:1px solid #eee">'+r.currency+'</td><td style="padding:7px 14px;border-bottom:1px solid #eee;text-align:right">'+r.count+'</td><td style="padding:7px 14px;border-bottom:1px solid #eee;text-align:right;font-weight:700">'+r.total+'</td></tr>').join('')||'<tr><td colspan="3" style="padding:10px 14px;color:#999;font-style:italic">No verified invoices today</td></tr>';
const errLines=Object.entries(d.topErrors).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([msg,cnt])=>'<li style="margin-bottom:4px">'+msg+' <span style="color:#999;font-size:12px">('+cnt+'x)</span></li>').join('')||'<li style="color:#999;font-style:italic">No flagging errors today</li>';
const card=(label,value,color)=>'<div style="flex:1;min-width:100px;background:#fff;border-radius:8px;padding:16px;border:1px solid #e8e8e8;text-align:center"><div style="font-size:11px;color:#888;text-transform:uppercase;margin-bottom:6px">'+label+'</div><div style="font-size:26px;font-weight:700;color:'+(color||'#222')+'">'+value+'</div></div>';
const html='<div style="font-family:Arial,sans-serif;max-width:640px;margin:0 auto"><div style="background:#0f6e56;padding:24px 32px;border-radius:10px 10px 0 0"><h2 style="color:#fff;margin:0;font-size:20px">Invoice Audit Daily Digest</h2><p style="color:#9fe1cb;margin:5px 0 0">'+d.today+'</p></div><div style="background:#f7f7f5;padding:24px 32px"><div style="display:flex;gap:12px;margin-bottom:24px;flex-wrap:wrap">'+card('Processed',d.totalCount,'#222')+card('Pass Rate',d.passRate+'%','#0f6e56')+card('Flagged',d.flaggedCount,'#c04828')+card('Needs Review',d.needsReviewCount,'#e67e22')+card('Total Amount',d.totalAmount,'#222')+'</div><h3 style="font-size:13px;font-weight:700;margin:0 0 10px;color:#444">Currency Breakdown</h3><table style="width:100%;border-collapse:collapse;background:#fff;border-radius:8px;border:1px solid #e8e8e8;margin-bottom:24px"><thead><tr style="background:#f1efe8"><th style="padding:9px 14px;text-align:left;font-size:12px;color:#666">Currency</th><th style="padding:9px 14px;text-align:right;font-size:12px;color:#666">Invoices</th><th style="padding:9px 14px;text-align:right;font-size:12px;color:#666">Total</th></tr></thead><tbody>'+currTable+'</tbody></table><h3 style="font-size:13px;font-weight:700;margin:0 0 10px;color:#444">Top Flag Reasons</h3><ul style="margin:0;padding:14px 14px 14px 30px;font-size:13px;background:#fff;border-radius:8px;border:1px solid #e8e8e8">'+errLines+'</ul>'+(d.avgConf!==null?'<p style="margin:16px 0 0;font-size:12px;color:#888">Avg AI confidence on verified: <b>'+d.avgConf+'%</b> &middot; Duplicates caught: <b>'+d.dupCount+'</b></p>':'')+'</div><div style="background:#e8e8e8;padding:10px 32px;border-radius:0 0 10px 10px;font-size:11px;color:#999;text-align:center">Invoice Vision Auditor &middot; n8n + Gemini 2.5 Flash</div></div>';
return [{json:{subject:'Invoice Digest '+d.today+' â€” '+d.verifiedCount+' verified, '+d.flaggedCount+' flagged, '+d.needsReviewCount+' needs review',html}}];

